package main

import (
	"fmt"
	"net/http"
	"strconv"
	"strings"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

type userRequest struct {
	UserID   int
	RequestID string
}

var (
	requestsTotal = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "request_total",
			Help: "Total number of requests per user",
		},
		[]string{"user_id", "request_id"},
	)
)

func init() {
	prometheus.Register(requestsTotal)
}

func handler(w http.ResponseWriter, r *http.Request) {
	parts := strings.Split(r.URL.Path, "/")
	userID, _ := strconv.Atoi(parts[1])
	requestID := parts[2]

	requestsTotal.WithLabelValues(strconv.Itoa(userID), requestID).Inc()
	fmt.Fprintf(w, "Hello from user %d and request %s", userID, requestID)
}

func main() {
	http.HandleFunc("/users/{user_id}/requests/{request_id}", handler)
	http.ListenAndServe(":8080", nil)
}